/*DisPrmtMgmtMapper.getDisPrmtList*/
SELECT DIS.PRMT_ID AS prmtId ,DIS.PRMT_NM AS prmtNm ,DIS.STRT_DTTM AS strtDttm ,DIS.END_DTTM AS endDttm ,DIS.CHNL_TP AS chnlTp ,FN_GET_CODENM('CMN0090', DIS.CHNL_TP) AS chnlNm ,DIS.EVNT_CD AS evntCd ,FN_GET_CODENM('CMN0091', DIS.EVNT_CD) AS evntNm ,DIS.SLS_TP AS slsTp ,FN_GET_CODENM('CMN0093', DIS.SLS_TP) AS slsNm ,DIS.INTM_YN AS intmYn ,DIS.MODEL_ID AS modelId ,DIS.MODEL_NM AS modelNm ,DIS.ENGG_SRL AS enggSrl ,DIS.USG_YN AS usgYn ,DIS.REGST_ID AS regstId ,FN_GET_USRNM(DIS.REGST_ID) AS regstNm ,TO_CHAR(DIS.REGST_DTTM, 'YYYYMMDDHH24MISS') AS regstDttm ,DIS.RVISN_ID AS rvisnId ,FN_GET_USRNM(DIS.RVISN_ID) AS rvisnNm ,TO_CHAR(DIS.RVISN_DTTM, 'YYYYMMDDHH24MISS') AS rvisnDttm FROM MSP_DIS_MST DIS WHERE #{searchBaseDate} BETWEEN SUBSTR(DIS.STRT_DTTM, 1, 8) AND SUBSTR(DIS.END_DTTM, 1, 8)
AND UPPER(DIS.PRMT_NM) LIKE '%' || UPPER( #{searchPrmtNm} ) || '%'
AND DIS.CHNL_TP = #{searchChnlTp}
AND DIS.EVNT_CD = #{searchEvntCd}
AND DIS.SLS_TP = #{searchSlsTp}
AND EXISTS (SELECT 1 FROM MSP_DIS_ORG B WHERE DIS.PRMT_ID = B.PRMT_ID
AND FN_GET_ORGNM(B.ORGN_ID) LIKE '%' || #{orgnVal} || '%'
AND B.ORGN_ID = #{orgnVal}
)
AND EXISTS (SELECT 1 FROM MSP_DIS_SOC C WHERE DIS.PRMT_ID = C.PRMT_ID
AND FN_GET_RATENM(C.RATE_CD) LIKE '%' || #{pRateVal} || '%'
AND C.RATE_CD = #{pRateVal}
)
AND EXISTS (SELECT 1 FROM MSP_DIS_ADD D WHERE DIS.PRMT_ID = D.PRMT_ID
AND FN_GET_RATENM(D.SOC) LIKE '%' || #{rRateVal} || '%'
AND D.SOC = #{rRateVal}
)
AND DIS.USG_YN = 'Y' ORDER BY DIS.PRMT_ID DESC

/*DisPrmtMgmtMapper.getDisPrmtOrgnList*/ SELECT A.ORGN_ID AS orgnId ,A.ORGN_NM AS orgnNm ,B.CD_DSC AS typeNm ,FN_GET_CODENM('CMN0005', A.ORGN_STAT_CD) AS statNm FROM ORG_ORGN_INFO_MST A ,CMN_GRP_CD_MST B WHERE A.TYPE_DTL_CD3 = B.CD_VAL AND A.TYPE_CD = '20' AND B.GRP_ID = 'ORG0043' AND B.USG_YN = 'Y'
AND A.ORGN_NM LIKE '%'||#{orgnNm}||'%'
ORDER BY orgnNm

/*DisPrmtMgmtMapper.getDisPrmtSocList*/ SELECT A.RATE_CD AS rateCd ,A.RATE_NM AS rateNm ,A.BASE_AMT AS baseAmt FROM MSP_RATE_MST A WHERE A.APPL_END_DT = '99991231' AND A.SERVICE_TYPE = 'P' AND A.PAY_CL_CD = 'PO'
AND A.RATE_NM LIKE '%'||#{rateNm}||'%'
ORDER BY rateNm

/*DisPrmtMgmtMapper.getDisPrmtAddList*/ SELECT A.CD_VAL AS soc ,A.CD_DSC AS addNm ,B.BASE_AMT AS disAmt FROM CMN_GRP_CD_MST A ,MSP_RATE_MST B WHERE A.GRP_ID = 'RCP2042' AND A.CD_VAL = B.RATE_CD AND B.APPL_END_DT = '99991231'
AND A.CD_DSC LIKE '%'||#{addNm}||'%'
ORDER BY addNm

mapper.insert:

			SELECT 'F' || TO_CHAR(SYSDATE,'YYYYMMDD') || TRIM(TO_CHAR(SQ_DIS_MST.NEXTVAL, '0000000')) AS prmtId
			FROM   DUAL

			/*DisPrmtMgmtMapper.insertDisPrmtMst*/
			INSERT INTO MSP_DIS_MST (
				 PRMT_ID
				,PRMT_NM
				,STRT_DTTM
				,END_DTTM
				,CHNL_TP
				,EVNT_CD
				,SLS_TP
				,INTM_YN
				,MODEL_ID
				,MODEL_NM
				,ENGG_SRL
				,USG_YN
				,REGST_ID
				,REGST_DTTM
			) VALUES (
				 #{prmtId}
				,#{prmtNm}
				,#{strtDttm}
				,#{endDttm}
				,#{chnlTp}
				,#{evntCd}
				,#{slsTp}
				,#{intmYn}
				,#{modelId}
				,(SELECT PRDT_NM
                  FROM CMN_INTM_MDL
                  WHERE RPRS_PRDT_ID = #{modelId}
                  AND RPRS_YN = 'Y')
				,#{enggSrl}
				,NVL(#{usgYn}, 'Y')
				,#{sessionUserId}
				,SYSDATE
			)

