/*DisPrmtMgmtMapper.updDisPrmtByInfo*/
UPDATE  MSP_DIS_MST				
SET     RVISN_ID = #{sessionUserId}
		,RVISN_DTTM = SYSDATE


					,END_DTTM = #{endDttmMod}


					,USG_YN = 'N'


WHERE  PRMT_ID = #{prmtId}

