/*DisPrmtMgmtMapper.getDisPrmtDupByInfoExl*/ SELECT DISTINCT A.PRMT_ID AS prmtId ,B.ORGN_ID AS orgnId ,C.RATE_CD AS rateCd ,'1' AS typeCd ,'' AS regNum FROM MSP_DIS_MST A ,MSP_DIS_ORG B ,MSP_DIS_SOC C WHERE A.USG_YN = 'Y' AND A.PRMT_ID = B.PRMT_ID AND A.PRMT_ID = C.PRMT_ID AND #{strtDttm} <= A.END_DTTM AND #{endDttm} >= A.STRT_DTTM AND A.EVNT_CD = #{evntCd} AND A.SLS_TP = #{slsTp} AND A.INTM_YN = #{intmYn}
AND A.MODEL_ID = #{modelId}
AND ((A.ENGG_SRL = '001218243036')
OR A.ENGG_SRL LIKE '%' || #{enggCnt0} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt12} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt18} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt24} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt30} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt36} || '%'
) UNION SELECT DISTINCT A.PRMT_ID AS prmtId ,B.ORGN_ID AS orgnId ,C.RATE_CD AS rateCd ,'2' AS typeCd ,A.REG_NUM AS regNum FROM MSP_DIS_MST_CHK A ,MSP_DIS_ORG_CHK B ,MSP_DIS_SOC_CHK C WHERE A.USG_YN = 'Y' AND A.PRMT_ID = B.PRMT_ID AND A.PRMT_ID = C.PRMT_ID AND #{strtDttm} <= A.END_DTTM AND #{endDttm} >= A.STRT_DTTM AND A.EVNT_CD = #{evntCd} AND A.SLS_TP = #{slsTp} AND A.INTM_YN = #{intmYn}
AND A.MODEL_ID = #{modelId}
AND ((A.ENGG_SRL = '001218243036')
OR A.ENGG_SRL LIKE '%' || #{enggCnt0} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt12} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt18} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt24} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt30} || '%'
OR A.ENGG_SRL LIKE '%' || #{enggCnt36} || '%'
)

