		/*DisPrmtMgmtMapper.insertDisPrmtMstChk*/

			SELECT 	'F' || TO_CHAR(SYSDATE,'YYYYMMDD') || TRIM(TO_CHAR(SQ_DIS_MST.NEXTVAL, '0000000')) AS prmtId
			FROM  	 DUAL

			INSERT INTO MSP_DIS_MST_CHK (
					 PRMT_ID
					,PRMT_NM
					,STRT_DTTM
					,END_DTTM
					,CHNL_TP
					,EVNT_CD
					,SLS_TP
					,INTM_YN
					,MODEL_ID
					,MODEL_NM
					,ENGG_SRL
					,USG_YN
					,REGST_ID
					,REGST_DTTM
					,REG_NUM
			)
			VALUES (
					 #{prmtId}
					,#{prmtNm}
					,#{strtDttm}
					,#{endDttm}
					,#{chnlTp}
					,#{evntCd}
					,#{slsTp}
					,#{intmYn}
					,#{modelId}
					,(SELECT PRDT_NM
                      FROM CMN_INTM_MDL
                      WHERE RPRS_PRDT_ID = #{modelId}
                      	AND RPRS_YN = 'Y')
					,#{enggSrl}
					,NVL(#{usgYn}, 'Y')
					,#{sessionUserId}
					,SYSDATE
					,#{regNum}
			)

