/*DisPrmtMgmtMapper.getDisPrmtListCombo*/ SELECT DISTINCT PRMT_NM, PRMT_ID, TO_CHAR((SELECT SUM(A.BASE_AMT) FROM MSP_RATE_MST A, MSP_DIS_ADD B WHERE A.RATE_CD = B.SOC AND B.PRMT_ID = VW_DIS_PRMT_DTL.PRMT_ID)) AS DIS_CNT FROM VW_DIS_PRMT_DTL WHERE 1 = 1 AND TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN STRT_DTTM AND END_DTTM AND USG_YN = 'Y'
AND EVNT_CD = 'NAC'
AND EVNT_CD = 'C07'
AND 1=0
AND SLS_TP = (SELECT ETC1 FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0092' AND CD_VAL = #{slsTp})
AND INTM_YN = 'N'
AND INTM_YN = 'Y' AND MODEL_ID = #{modelId}
AND ENGG_SRL LIKE '%' || #{enggSrl} || '%' AND ORGN_ID = #{orgnId} AND RATE_CD = #{rateCd}

/*DisPrmtMgmtMapper.getDisChoChrgPrmtListExcelDown*/ SELECT DENSE_RANK() OVER (ORDER BY A.PRMT_ID) AS rnum , A.PRMT_NM AS prmtNm , TO_CHAR(SYSDATE+1, 'YYYYMMDD') AS strtDt , '000000' AS strtTm , '20991231' AS endDt , '235959' AS endTm , A.CHNL_TP AS chnlTp , A.EVNT_CD AS evntCd , A.SLS_TP AS slsTp , A.INTM_YN AS intmYn , A.MODEL_ID AS modelId , A.ENGG_SRL AS enggSrl , '조직코드' AS orgnId , B.RATE_CD AS rateCd , C.SOC AS soc FROM MSP_DIS_MST A , MSP_DIS_SOC B , MSP_DIS_ADD C WHERE 1=1 AND A.PRMT_ID IN
#{item}
AND A.PRMT_ID = B.PRMT_ID AND A.PRMT_ID = C.PRMT_ID
